import { CommonModule } from '@angular/common';
import {
  Component,
  Input,
  OnChanges,
  OnInit,
  SimpleChanges,
  ChangeDetectorRef,
  inject,
  OnDestroy,
} from '@angular/core';
import { FormControl } from '@angular/forms';
import { TranslateModule, TranslateService } from '@ngx-translate/core';
import { FNLabel } from 'fn-label';
import { Subscription, merge } from 'rxjs';
import { startWith } from 'rxjs/operators';

@Component({
  selector: 'fn-field-message',
  standalone: true,
  imports: [CommonModule, TranslateModule, FNLabel],
  template: `
    <fn-label variant="p4" [color]="statusColor" [label]="getFieldMessage()"></fn-label>
  `,
})
export class FNFieldMessage implements OnInit, OnChanges, OnDestroy {
  @Input() field: any;
  @Input() control?: FormControl;
  @Input() hasFocus: boolean = false;

  translate = inject(TranslateService);
  private readonly subs = new Subscription();

  constructor(private readonly cdr: ChangeDetectorRef) {}

  ngOnInit(): void {
    if (!this.control) {
      // ensure at least initial render works
      this.cdr.detectChanges();
      return;
    }

    // startWith ensures initial evaluation immediately
    const val$ = this.control.valueChanges.pipe(startWith(this.control.value));
    const status$ = this.control.statusChanges.pipe(startWith(this.control.status));

    // merge both streams so any change forces update
    this.subs.add(
      merge(val$, status$).subscribe(() => {
        // detectChanges to ensure inner OnPush children get updated immediately
        try {
          this.cdr.detectChanges();
        } catch {
          // ignore change-detection errors if they happen during CD cycle
          this.cdr.markForCheck();
        }
      }),
    );
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['hasFocus'] || changes['control']) {
      // ensure re-evaluation on parent-driven changes
      try {
        this.cdr.detectChanges();
      } catch {
        this.cdr.markForCheck();
      }
    }
  }

  ngOnDestroy(): void {
    this.subs.unsubscribe();
  }

  getFieldMessage(): string {
    // defensive: no control => show helper (initial server-side or static)
    if (!this.control) return this.field?.helperText || '';

    // show validation error message when touched + invalid
    if (this.control.touched && this.control.errors) {
      for (const key of Object.keys(this.control.errors)) {
        // Check if the error object has a 'message' property (for dynamic error messages)
        const errorValue = this.control.errors[key];
        if (errorValue && typeof errorValue === 'object' && errorValue.message) {
          return errorValue.message;
        }
        // Fallback to field.errors[key] for static error messages
        if (this.field?.errors?.[key]) {
          return this.field.errors[key];
        }
      }
      // fallback error message if no mapping provided
      return (
        this.field?.errors?.default || 'Please enter ' + this.translate.instant(this.field?.label)
      );
    }

    // default (untouched or other states): helper text
    return this.field?.helperText || '';
  }

  get statusColor(): string {
    if (this.control?.disabled) return '#c4cdd2'; // Base-30
    if (this.isError) return '#ef3e42'; // RHB-Red-100
    if (this.isSuccess) return '#6cc24a'; // Green-100
    return '#0067b1'; // RHB-Blue-100 (Helper)
  }

  get isError(): boolean {
    return !!(this.control?.touched && this.control?.errors);
  }

  get isSuccess(): boolean {
    return !!(this.control?.valid && this.control?.touched);
  }

  get isHelper(): boolean {
    return true;
  }
}
